```python
class DateTimeField(fields.DateTimeField):
    def to_python(self, value, timezone_in_use):
        import pytz
        # noinspection PyPackageRequirements
        from dateutil import parser as dt_parser

        try:
            return super(DateTimeField, self).to_python(value, timezone_in_use)
        except ValueError as e:
            if 'does not match format' in text_type(e):
                LOGGER.warning("Default datetime serializer failed on '%s'", value)
                dt = dt_parser.parse(value)
                return timezone_in_use.localize(dt).astimezone(pytz.utc)
            raise
